/**
 * CodeGraph bridge for kdoc MCP server.
 * Probes for CodeGraph availability and provides degraded fallback
 * with grep-based heuristics when CodeGraph is unavailable.
 */

import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { join, relative, extname, basename } from 'node:path';
import { spawnSync } from 'node:child_process';

export interface CodegraphStatus {
  available: boolean;
  dbPath?: string;
  reason?: string;
}

export interface DegradedResult {
  degraded: true;
  reason: string;
  partialResults: Array<{ path: string; status: string; details?: string }>;
  confidence: 'low' | 'medium';
}

export interface ReconcileResult {
  degraded: boolean;
  driftItems: Array<{ doc: string; finding: string; severity: 'info' | 'warning' | 'error' }>;
  confidence: 'low' | 'medium' | 'high';
  reason?: string;
}

export interface ImpactResult {
  degraded: boolean;
  affectedDocs: Array<{ doc: string; reason: string; confidence: 'low' | 'medium' | 'high' }>;
  reason?: string;
}

/**
 * Check if CodeGraph is available for a project.
 */
export function checkCodegraph(projectDir: string): CodegraphStatus {
  const dbPath = join(projectDir, '.codegraph', 'graph.db');
  if (existsSync(dbPath)) {
    return { available: true, dbPath };
  }
  return { available: false, reason: 'CodeGraph database not found at .codegraph/graph.db' };
}

// ---------------------------------------------------------------------------
// Grep-based heuristics for degraded mode
// ---------------------------------------------------------------------------

/**
 * Find exported function/class names in source files using grep.
 */
function grepExports(scanPath: string): string[] {
  try {
    const result = spawnSync('grep', [
      '-rn', '--include=*.ts', '--include=*.js', '--include=*.tsx', '--include=*.jsx',
      '-E', '^export (function|class|const|type|interface|enum) ',
      scanPath,
    ], { encoding: 'utf8', timeout: 10000 });

    if (!result.stdout) return [];

    return result.stdout.split('\n')
      .filter(Boolean)
      .map(line => {
        const match = line.match(/export (?:function|class|const|type|interface|enum) (\w+)/);
        return match ? match[1] : '';
      })
      .filter(Boolean);
  } catch {
    return [];
  }
}

/**
 * Collect all .md files recursively under a directory.
 */
function walkMdFiles(dir: string): string[] {
  const results: string[] = [];
  if (!existsSync(dir)) return results;
  try {
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      const full = join(dir, entry.name);
      if (entry.isDirectory()) {
        results.push(...walkMdFiles(full));
      } else if (entry.isFile() && extname(entry.name) === '.md') {
        results.push(full);
      }
    }
  } catch {
    // Ignore permission errors
  }
  return results;
}

/**
 * Search Knowledge docs for references to a symbol name.
 */
function findSymbolInDocs(knowledgeRoot: string, symbolName: string): string[] {
  const docs = walkMdFiles(knowledgeRoot);
  const matches: string[] = [];

  for (const doc of docs) {
    try {
      const content = readFileSync(doc, 'utf8');
      if (content.includes(symbolName)) {
        matches.push(relative(knowledgeRoot, doc));
      }
    } catch {
      // Skip unreadable files
    }
  }
  return matches;
}

// ---------------------------------------------------------------------------
// Degraded mode implementations
// ---------------------------------------------------------------------------

/**
 * Build a degraded reconciliation result using grep heuristics.
 */
export function degradedReconcile(repoPath: string, scanPath: string): ReconcileResult {
  const knowledgeRoot = join(repoPath, 'Knowledge');
  if (!existsSync(knowledgeRoot)) {
    return {
      degraded: true,
      driftItems: [{ doc: 'Knowledge/', finding: 'Knowledge directory not found', severity: 'error' }],
      confidence: 'low',
      reason: 'CodeGraph not available and Knowledge directory missing',
    };
  }

  // Grep for exported symbols in the scan path
  const exports = grepExports(scanPath);
  const driftItems: ReconcileResult['driftItems'] = [];

  if (exports.length === 0) {
    driftItems.push({
      doc: scanPath,
      finding: 'No exported symbols found via grep — cannot verify documentation coverage',
      severity: 'info',
    });
  } else {
    // Check which exports are referenced in Knowledge docs
    const documented = new Set<string>();
    const undocumented: string[] = [];

    for (const exp of exports.slice(0, 50)) { // Limit to avoid performance issues
      const refs = findSymbolInDocs(knowledgeRoot, exp);
      if (refs.length > 0) {
        documented.add(exp);
      } else {
        undocumented.push(exp);
      }
    }

    if (undocumented.length > 0) {
      driftItems.push({
        doc: scanPath,
        finding: `${undocumented.length} exported symbol(s) not referenced in Knowledge docs: ${undocumented.slice(0, 5).join(', ')}${undocumented.length > 5 ? '...' : ''}`,
        severity: 'warning',
      });
    }

    if (documented.size > 0) {
      driftItems.push({
        doc: scanPath,
        finding: `${documented.size} exported symbol(s) found in Knowledge docs`,
        severity: 'info',
      });
    }
  }

  return {
    degraded: true,
    driftItems,
    confidence: 'low',
    reason: 'CodeGraph not available — using grep-based heuristics',
  };
}

/**
 * Build a degraded impact result using path-based heuristics.
 */
export function degradedImpact(repoPath: string, changedFiles: string[]): ImpactResult {
  const knowledgeRoot = join(repoPath, 'Knowledge');
  if (!existsSync(knowledgeRoot)) {
    return {
      degraded: true,
      affectedDocs: [],
      reason: 'Knowledge directory not found',
    };
  }

  const affectedDocs: ImpactResult['affectedDocs'] = [];

  for (const file of changedFiles) {
    // Extract module/directory name from the changed file path
    const parts = file.split('/');
    const moduleName = basename(file, extname(file));
    const dirName = parts.length > 1 ? parts[parts.length - 2] : '';

    // Search Knowledge docs for references to the file/module name
    const byName = findSymbolInDocs(knowledgeRoot, moduleName);
    const byDir = dirName ? findSymbolInDocs(knowledgeRoot, dirName) : [];

    const allMatches = [...new Set([...byName, ...byDir])];
    for (const doc of allMatches) {
      affectedDocs.push({
        doc,
        reason: `References "${moduleName}" or "${dirName}" from changed file ${file}`,
        confidence: 'low',
      });
    }
  }

  return {
    degraded: true,
    affectedDocs,
    reason: 'CodeGraph not available — using path/name heuristics',
  };
}
